PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE daily_absences (     date TEXT,      teacher_id TEXT,      PRIMARY KEY (date, teacher_id) );
CREATE TABLE login_attempts (ip TEXT PRIMARY KEY, failures INT, block_until INT);
CREATE TABLE access_logs_v2 (
        ip_address TEXT PRIMARY KEY,
        attempts INTEGER,
        blocked_until INTEGER
      );
CREATE TABLE access_logs_v3 (
        ip_address TEXT PRIMARY KEY,
        attempts INTEGER,
        blocked_until INTEGER
      );
CREATE TABLE students (     roll_no TEXT PRIMARY KEY,     email TEXT UNIQUE NOT NULL,     semester TEXT,     section TEXT,     password TEXT NOT NULL,     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE society_events (     id INTEGER PRIMARY KEY AUTOINCREMENT,     society_name TEXT NOT NULL,     event_name TEXT NOT NULL,     event_date TEXT NOT NULL,     event_time TEXT NOT NULL,     location TEXT NOT NULL,     event_type TEXT NOT NULL,     description TEXT,     registration_link TEXT NOT NULL,     is_active INTEGER DEFAULT 1,     created_at DATETIME DEFAULT CURRENT_TIMESTAMP , is_pinned INTEGER DEFAULT 0);
CREATE TABLE event_analytics (     event_id INTEGER PRIMARY KEY,     views INTEGER DEFAULT 0,     clicks INTEGER DEFAULT 0,     FOREIGN KEY (event_id) REFERENCES society_events(id) ON DELETE CASCADE );
CREATE TABLE daily_event_analytics (     id INTEGER PRIMARY KEY AUTOINCREMENT,     event_id INTEGER,     log_date TEXT DEFAULT (CURRENT_DATE),   views INTEGER DEFAULT 0,     clicks INTEGER DEFAULT 0,     UNIQUE(event_id, log_date),      FOREIGN KEY (event_id) REFERENCES society_events(id) ON DELETE CASCADE );
CREATE TABLE campus_rooms (id TEXT PRIMARY KEY, name TEXT NOT NULL, type TEXT NOT NULL, emptySlots TEXT NOT NULL, occupiedBy TEXT NOT NULL DEFAULT '{}', last_updated TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE teachers (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    department TEXT,
    access_code TEXT UNIQUE NOT NULL
);
CREATE TABLE faculty_schedules (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    department TEXT,
    schedule TEXT DEFAULT '{}'
);
CREATE TABLE teachers_email (id TEXT PRIMARY KEY, email TEXT NOT NULL);
CREATE TABLE global_absences (id INTEGER PRIMARY KEY AUTOINCREMENT, teacher_id TEXT, start_date TEXT, end_date TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
DELETE FROM sqlite_sequence;
